{"output":"import { useEffect } from 'react';
import { Flex, Text } from '@chakra-ui/react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { districtCodes, regionOptions } from '@domain/constants/regionOptions';
import { useGetAccount } from '@state/accounts';
import { FormInputControl } from '@ui/components/formControls/InputControl';
import { FormRadioGroup, RadioControl } from '@ui/components/formControls/RadioButtonGroup';
import { FormSelectControl } from '@ui/components/formControls/SelectControl/FormSelectControl';
import { SUBCATEGORY_TYPES } from './constants';

const isValidSubCategoryKey = (key: string): key is keyof typeof SUBCATEGORY_TYPES => {
  return key in SUBCATEGORY_TYPES;
};

// "Directory Name" is our term for rep name + state + district (if necessary) e.g. "John Smith (CA - 03)"
const getDirectoryName = ({
  district,
  name,
  selectedSubCategoryType,
  state,
}: {
  district?: string;
  name: string;
  selectedSubCategoryType: string;
  state?: string;
}) => {
  if (selectedSubCategoryType === 'federal_president_8651') {
    return `${name} (President)`;
  }

  if (selectedSubCategoryType === 'federal_senate_8651') {
    return `${name} (${state || '--'})`;
  }

  if (selectedSubCategoryType === 'federal_house_8651') {
    return `${name} (${state || '--'} - ${district || '--'})`;
  }

  return name;
};

export const SubCategoryType = () => {
  const { t } = useTranslation('organizationApplication', {
    keyPrefix: 'category.subCategoryType',
  });
  const { t: tAccount } = useTranslation('accounts');

  const { currentAccount } = useGetAccount();

  const { register, setValue, watch } = useFormContext();

  const selectedSubCategoryType: typeof SUBCATEGORY_TYPES.federal[number] =
    watch('subCategoryType');
  const candidateName = watch('candidateName');
  const selectedState = watch('candidateState');
  const selectedDistrict = watch('candidateDistrict');
  const isFederalSubCategory =
    typeof selectedSubCategoryType === 'string' &&
    (SUBCATEGORY_TYPES.federal as readonly string[]).includes(selectedSubCategoryType);
  const computedDirectoryName =
    isFederalSubCategory && candidateName
      ? getDirectoryName({
          district: selectedDistrict || undefined,
          name: candidateName,
          selectedSubCategoryType,
          state: selectedState || undefined,
        })
      : '';

  useEffect(() => {
    register('directoryName', { value: '' });
  }, [register]);

  useEffect(() => {
    setValue('directoryName', computedDirectoryName, {
      shouldDirty: false,
      shouldTouch: false,
    });
  }, [computedDirectoryName, setValue]);

  const isCategoryType = ['church-ministry', 'vendor'].includes(currentAccount?.category as string);
  const subCategoryKey = isCategoryType ? 'category' : 'subCategory';
  const categoryOrSubCategory = currentAccount?.[subCategoryKey] || '';

  const label = t(`heading.${categoryOrSubCategory}` as Parameters<typeof t>[0]);

  if (!isValidSubCategoryKey(categoryOrSubCategory)) {
    // todo: some graceful error handling
    console.error(`No SUBCATEGORY_TYPES for ${categoryOrSubCategory}`);
    return null;
  }
  const subCategoryTypes = SUBCATEGORY_TYPES[categoryOrSubCategory];

  return (
    <FormRadioGroup isRequired label={label} name="subCategoryType">
      <Flex alignItems="flex-start" direction="column" gap={2}>
        {subCategoryTypes?.map((subCategoryType) => (
          <Flex alignItems="flex-start" direction="column" gap={2} key={subCategoryType}>
            <Flex alignItems="center" gap={4}>
              <RadioControl key={subCategoryType} value={subCategoryType}>
                {tAccount(
                  `subcategoryType.${categoryOrSubCategory}.${subCategoryType}` as Parameters<
                    typeof tAccount
                  >[0]
                )}
              </RadioControl>

              {selectedSubCategoryType === subCategoryType && computedDirectoryName && (
                <Text color="gray.500" fontSize="md">
                  {computedDirectoryName}
                </Text>
              )}
            </Flex>
            {selectedSubCategoryType === subCategoryType && (
              <>
                {SUBCATEGORY_TYPES.federal.includes(subCategoryType) && (
                  <FormInputControl
                    isRequired
                    label="Candidate Name"
                    name="candidateName"
                    type="text"
                  />
                )}
                {(selectedSubCategoryType === 'federal_senate_8651' ||
                  selectedSubCategoryType === 'federal_house_8651') && (
                  <FormSelectControl
                    isRequired
                    label="State"
                    name="candidateState"
                    options={regionOptions.us}
                    placeholder="-"
                  />
                )}
                {selectedSubCategoryType === 'federal_house_8651' && (
                  <FormSelectControl
                    isRequired
                    label="District"
                    name="candidateDistrict"
                    options={districtCodes}
                    placeholder="-"
                  />
                )}
              </>
            )}
          </Flex>
        ))}
      </Flex>
    </FormRadioGroup>
  );
};
